var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"…이해가 안 가.","JPN":"……理解できないわ。","ENG":"...I still don't get it.","TWN":"……我不太懂。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그 잘난 상판을 보기 위해 20년이나 기다려야 했다는 게.","JPN":"その面を見るまで20年もかかってしまったってことが。","ENG":"That I had to wait twenty years just to see that smug face of yours.","TWN":"為了再看一眼你那張了不起的臉，居然得等上20年。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그늘 속에 숨어버린 날 찾아야 할 만큼 지금 상황이 심상치 않다는 거겠지?","JPN":"表から身を引いていた私を探さなきゃいけないほど、今の状況が芳しくないってことでしょうね。","ENG":"If you had to come looking for me while I was keeping myself hidden, then things must be pretty serious right now, right?","TWN":"現在的情況已經嚴重到，必須去找那個躲進陰影裡的你了吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"아까 대충 당신네 회사를 훑어봤는데 말이지… 익숙한 얼굴들이 좀 보이더라고.","JPN":"さっきあなたの会社をざっと見せてもらったけど……見慣れた顔がいくつかあったわ。","ENG":"I took a quick look around your company earlier... and I spotted a few familiar faces.","TWN":"剛才我大概瀏覽了你們公司……看到一些熟面孔呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"당신의 방식을 잘 알고 있는 그 사람들이 또다시 당신 곁으로 모였다는 것은…….","JPN":"あなたのやり方をよく知っている彼らが、再びあなたの下に集ったってことは……","ENG":"The fact that people who know your way of doing things so well have gathered around you again...","TWN":"那些很清楚你做事方式的人，再次聚集在你身邊這件事……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"여전히 당신이 세계를 구하기 위해 움직이고 있다는 뜻이겠지.","JPN":"あなたは今も変わらず、世界を救おうとしているのね。","ENG":"Must mean that you're still moving to save the world.","TWN":"就代表你現在，依然在為了拯救世界行動吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"전대장님이 그렇게 된 이후… 20년 동안 퓨처 앳 워에 틀어박혀 연구에 집중했어.","JPN":"戦隊長の背中を見送ってから……20年間、フューチャーアットウォーに引きこもって研究に没頭したわ。","ENG":"After Commander ended up that way... I shut myself away in Future-at-War and focused on my research for twenty years.","TWN":"自從戰隊長出事之後……這20年來，我一直把自己關在天啟兵器，專心投入研究。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"동결된 부전대장님을 깨우기 위해선 특수한 설비가 필요했거든.","JPN":"凍結された副戦隊長を目覚めさせるためには、特殊な設備が必要だったから。","ENG":"To wake the frozen Deputy Commander, specialized facilities were necessary.","TWN":"因為要喚醒被凍結的副隊長，需要特殊的設備。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"뭐… 단순히 그곳의 인프라를 이용할 생각뿐이었지만…….","JPN":"まあ……最初は単に、そこのインフラを利用したいだけだったんだけど……","ENG":"Well... At first, I only planned to make use of their infrastructure...","TWN":"嗯……我原本也只是打算借用那裡的基礎設施而已……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"퓨처 앳 워 프로젝트의 사람들, 마치 예전의 우리를 보는 것 같았어.","JPN":"フューチャーアットウォープロジェクトの人々は、まるで昔の私たちのようだった。","ENG":"But the people involved in the Future-at-War project felt just like looking at who we used to be.","TWN":"看著天啟兵器計畫裡的那些人，好像看到了過去的我們。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"사람들을 구하고자 하는 마음. 꼭 우리 전대장님을 보는 것 같았지.","JPN":"人々を助けようとする気持ち。戦隊長を見ているみたいだった。","ENG":"That desire to save others. It was just like seeing our Commander again.","TWN":"那份想拯救他人的心意，簡直就像在看戰隊長本人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"사그라들었던 내 마음에… 그 사람들이 다시 불을 붙여준 거야.","JPN":"彼らが……燻っていた私の心に、また火をつけてくれたの。","ENG":"They lit a fire again in my heart... that had nearly burned out.","TWN":"就是他們再次點燃了……我早已冷卻的心。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"시간… 돈… 기술… 나에게 부족하다고 생각했던 모든 것을 준비했지.\xA0","JPN":"時間……金……技術……私に足りないと思っていたすべてを用意したわ。","ENG":"Time... Money... Technology... I prepared everything I thought I was lacking.","TWN":"時間……金錢……技術……我把我覺得不夠的一切，都準備好了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"…다시는 그때와 같은 후회를 반복하지 않기 위해서.","JPN":"……二度とあの時と同じ後悔を繰り返さないために。","ENG":"...So that I would never repeat the same regrets as back then.","TWN":"……就是為了不再重蹈覆轍，落得當年的下場。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"난 여전히 당신, 그리고 관리국이 마음에 들지 않아.","JPN":"私は今もあなたが、そして管理局が気に入らない。","ENG":"I still don't like you or the Administration.","TWN":"我依然不喜歡你，也不喜歡管理局。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"하지만 당신과 협력하는 이유는 단 하나야.","JPN":"それでもあなたに協力する理由はひとつ。","ENG":"But there's only one reason I'm working with you.","TWN":"但我會選擇與你合作，理由只有一個。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"전대장님이라면… 그러셨을 테니까.","JPN":"戦隊長なら……そうしたはずだから。","ENG":"Because if Commander were still here... she'd make the same choice.","TWN":"如果是戰隊長……他一定也會這麼做。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그분의 의지와… 꿈, 그리고 믿음은… 절대 틀리지 않았을 테니까.","JPN":"あの人の意志と……夢、そして信じる心は……絶対、間違っていなかったから。","ENG":"Her will... dreams, and faith... There's no way any of that was wrong.","TWN":"因為他的意志……夢想，還有他的信念……絕對不會出錯。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};